import{_ as a,o,c as l,ag as r}from"./chunks/framework.Vng7Hdlh.js";const p=JSON.parse('{"title":"20. Googleレビュー連携と満足度評価","description":"","frontmatter":{},"headers":[],"relativePath":"tenant/20-google-review.md","filePath":"tenant/20-google-review.md"}'),t={name:"tenant/20-google-review.md"};function i(n,e,s,h,c,g){return o(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="_20-googleレビュー連携と満足度評価" tabindex="-1">20. Googleレビュー連携と満足度評価 <a class="header-anchor" href="#_20-googleレビュー連携と満足度評価" aria-label="Permalink to &quot;20. Googleレビュー連携と満足度評価&quot;">​</a></h1><p>POSLAには、お客さんの満足度を収集し、高評価のお客さんをGoogleレビューに誘導する仕組みがあります。</p><h2 id="_20-1-満足度評価の仕組み" tabindex="-1">20.1 満足度評価の仕組み <a class="header-anchor" href="#_20-1-満足度評価の仕組み" aria-label="Permalink to &quot;20.1 満足度評価の仕組み&quot;">​</a></h2><h3 id="評価のタイミング" tabindex="-1">評価のタイミング <a class="header-anchor" href="#評価のタイミング" aria-label="Permalink to &quot;評価のタイミング&quot;">​</a></h3><p>お客さんのセルフオーダー画面で、注文品目が全て「served（提供済）」になると、満足度評価のプロンプトが表示されます。</p><h3 id="評価の方法" tabindex="-1">評価の方法 <a class="header-anchor" href="#評価の方法" aria-label="Permalink to &quot;評価の方法&quot;">​</a></h3><p>星（またはフェイス）ベースの評価インターフェースが表示されます。お客さんは直感的に満足度を入力できます。</p><h3 id="評価データの活用" tabindex="-1">評価データの活用 <a class="header-anchor" href="#評価データの活用" aria-label="Permalink to &quot;評価データの活用&quot;">​</a></h3><ul><li>スタッフ評価レポートで平均評価として集計されます</li><li>個別の注文に紐づいて記録されます</li></ul><hr><h2 id="_20-2-googleレビューへの誘導" tabindex="-1">20.2 Googleレビューへの誘導 <a class="header-anchor" href="#_20-2-googleレビューへの誘導" aria-label="Permalink to &quot;20.2 Googleレビューへの誘導&quot;">​</a></h2><h3 id="設定方法" tabindex="-1">設定方法 <a class="header-anchor" href="#設定方法" aria-label="Permalink to &quot;設定方法&quot;">​</a></h3><ol><li>管理ダッシュボードの「店舗設定」→「営業設定」を開きます</li><li>「Googleレビュー設定」セクションのGoogle Place IDを入力します</li></ol><p><strong>Google Place IDの取得方法：</strong></p><ol><li><a href="https://www.google.com/maps" target="_blank" rel="noreferrer">Google Maps</a> で自店舗を検索します</li><li>店舗の詳細ページのURLからPlace IDを取得します</li><li>または <a href="https://developers.google.com/maps/documentation/places/web-service/place-id" target="_blank" rel="noreferrer">Place ID Finder</a> を使用します</li></ol><h3 id="誘導の流れ" tabindex="-1">誘導の流れ <a class="header-anchor" href="#誘導の流れ" aria-label="Permalink to &quot;誘導の流れ&quot;">​</a></h3><ol><li>お客さんが満足度評価で**4つ星以上（高評価）**を付けます</li><li>「ありがとうございます！Googleでレビューを書いていただけませんか？」というメッセージとリンクが表示されます</li><li>リンクをタップするとGoogleマップのレビュー投稿画面が開きます</li></ol><p><strong>3つ星以下（低評価）の場合：</strong> Googleレビューへのリンクは表示されません。これにより、低評価のレビューがGoogleに直接投稿されるリスクを軽減します。</p><div class="tip custom-block"><p class="custom-block-title">Googleレビューの重要性</p><p>Googleマップでの高評価とレビュー数は、新規顧客の集客に大きく影響します。満足したお客さんを自然にレビュー投稿へ誘導することで、店舗の評価向上が期待できます。</p></div>',19)])])}const _=a(t,[["render",i]]);export{p as __pageData,_ as default};
